// --- ferratomic-core/src/schema_evolution.rs (MODIFIED) ---

// NEW helpers:
fn lww_bytes(doc: &str) -> AttributeDef {
    AttributeDef::new(ValueType::Bytes, Cardinality::One, ResolutionMode::Lww, Some(Arc::from(doc)))
}
fn mv_ref(doc: &str) -> AttributeDef {
    AttributeDef::new(ValueType::Ref, Cardinality::Many, ResolutionMode::MultiValue, Some(Arc::from(doc)))
}

// MODIFIED: define_tx_schema
// Was 5 attrs (tx/time, tx/agent, tx/provenance, tx/rationale, tx/coherence-override)
// Now 11 attrs with C8 renames + federation + derivation
fn define_tx_schema(schema: &mut Schema) {
    // Original 5 (with C8 renames):
    schema.define(Attribute::from("tx/time"),
        lww_instant("Transaction wall-clock time"));
    schema.define(Attribute::from("tx/origin"),              // C8: was tx/agent
        lww_ref("Node that originated this transaction"));
    schema.define(Attribute::from("tx/provenance"),
        lww_kw("Provenance type keyword"));                  // CHANGED: was lww_str
    schema.define(Attribute::from("tx/rationale"),
        lww_str("Why this transaction exists"));
    schema.define(Attribute::from("tx/validation-override"),  // C8: was tx/coherence-override
        lww_str("Manual validation exemption"));

    // NEW: INV-FERR-051 signing (3 attrs)
    schema.define(Attribute::from("tx/signature"),
        lww_bytes("Ed25519 transaction signature"));
    schema.define(Attribute::from("tx/signer"),
        lww_bytes("Ed25519 verifying key of signer"));
    schema.define(Attribute::from("tx/predecessor"),          // INV-FERR-061
        mv_ref("Causal predecessor transaction refs"));

    // NEW: D20 derivation chain (3 attrs)
    schema.define(Attribute::from("tx/derivation-source"),    // Phase 4a.5: user-assertion, etc.
        lww_kw("How this transaction was produced"));
    schema.define(Attribute::from("tx/derivation-rule"),      // Phase 4d: which Datalog rule
        lww_kw("Datalog rule that derived this transaction"));
    schema.define(Attribute::from("tx/derivation-input"),     // Phase 4d: input datom refs
        mv_ref("Input datom entities for this derivation"));
}

// genesis_schema() unchanged in signature — calls define_meta_schema + define_tx_schema

