// Total: 14 (meta/lattice) + 11 (tx) = 25 attributes
const GENESIS_ATTRIBUTE_IDENTS: [&str; 25] = [
    // db/* (9)
    "db/ident", "db/valueType", "db/cardinality", "db/doc",
    "db/unique", "db/isComponent", "db/resolutionMode",
    "db/latticeOrder", "db/lwwClock",
    // lattice/* (5)
    "lattice/ident", "lattice/elements", "lattice/comparator",
    "lattice/bottom", "lattice/top",
    // tx/* (11) — with C8 renames + federation + derivation
    "tx/time", "tx/origin", "tx/provenance", "tx/rationale",
    "tx/validation-override",
    "tx/signature", "tx/signer", "tx/predecessor",
    "tx/derivation-source", "tx/derivation-rule", "tx/derivation-input",
];

#[test]
fn test_inv_ferr_031_genesis_determinism() {
    let store = Store::genesis();
    assert_eq!(store.schema().len(), GENESIS_ATTRIBUTE_IDENTS.len(),
        "INV-FERR-031: genesis count must match expected idents");
    for ident in &GENESIS_ATTRIBUTE_IDENTS {
        assert!(store.schema().get(&Attribute::from(*ident)).is_some(),
            "INV-FERR-031: genesis missing: {ident}");
    }
    let store2 = Store::genesis();
    assert_eq!(store.schema(), store2.schema(),
        "INV-FERR-031: genesis must be deterministic");
}
