## Pseudocode Contract

```rust
// --- ferratom/src/bundle.rs (NEW) ---

use super::datom::{Attribute, Datom, Value};
use super::clock::TxId;
use super::signing::{TxSignature, TxSigner};
use super::provenance::ProvenanceType;

/// Transaction bundle for federation: preserves transaction boundaries
/// so signatures can be verified at the receiver (ADR-FERR-025).
///
/// The bundle separates user-asserted datoms from tx/* metadata datoms.
/// This is the natural unit of federation (D6): signatures cover the
/// user datoms, so they survive transport and merge intact.
///
/// INV-FERR-051: signature and signer fields.
/// INV-FERR-061: predecessors field (causal DAG).
/// INV-FERR-063: provenance field (epistemic weight).
///
/// ADR-FERR-010 constraint: Does NOT derive Serialize or Deserialize.
/// `Datom` and `Value` intentionally omit `Deserialize`. Transport
/// serialization uses Wire types (Phase 4c).
#[derive(Debug, Clone)]
pub struct SignedTransactionBundle {
    /// The transaction's HLC timestamp.
    pub tx_id: TxId,
    /// User-asserted datoms (excludes tx/* metadata).
    pub datoms: Vec<Datom>,
    /// Ed25519 signature (None for unsigned transactions).
    pub signature: Option<TxSignature>,
    /// Ed25519 verifying key (None for unsigned transactions).
    pub signer: Option<TxSigner>,
    /// Causal predecessor TxIds (INV-FERR-061).
    pub predecessors: Vec<TxId>,
    /// Provenance type (INV-FERR-063). Defaults to Observed.
    pub provenance: Option<ProvenanceType>,
}

/// Metadata attribute names used to separate user datoms from tx metadata.
const TX_SIGNATURE: &str = "tx/signature";
const TX_SIGNER: &str = "tx/signer";
const TX_PREDECESSOR: &str = "tx/predecessor";
const TX_PROVENANCE: &str = "tx/provenance";
const TX_TIME: &str = "tx/time";
const TX_ORIGIN: &str = "tx/origin";
const TX_RATIONALE: &str = "tx/rationale";
const TX_VALIDATION: &str = "tx/validation-override";
const TX_DERIVATION_SOURCE: &str = "tx/derivation-source";
const TX_DERIVATION_RULE: &str = "tx/derivation-rule";
const TX_DERIVATION_INPUT: &str = "tx/derivation-input";

impl SignedTransactionBundle {
    /// Reconstruct a bundle from store datoms grouped by TxId.
    /// Extracts tx/signature, tx/signer, tx/predecessor, tx/provenance
    /// metadata datoms; remaining datoms become the user payload.
    ///
    /// Metadata extraction is best-effort: if a tx/signature datom has
