/// D16: Compute transaction entity from TxId (content-addressed).
/// Replaces epoch-based format!("tx-{epoch}-{agent}").
fn tx_entity_from_txid(tx_id: TxId) -> EntityId {
    let mut bytes = Vec::with_capacity(28);
    bytes.extend_from_slice(&tx_id.physical().to_le_bytes());  // 8 bytes
    bytes.extend_from_slice(&tx_id.logical().to_le_bytes());   // 4 bytes
    bytes.extend_from_slice(tx_id.node().as_bytes());          // 16 bytes
    EntityId::from_content(&bytes)
}

// MODIFIED: create_tx_metadata takes tx_entity as param (no longer computes it)
// Was: fn create_tx_metadata(epoch: u64, node: NodeId, tx_id: TxId) -> Vec<Datom>
fn create_tx_metadata(
    tx_entity: EntityId,
    node: NodeId,
    tx_id: TxId,
) -> Vec<Datom> {
    let now_ms = i64::try_from(tx_id.physical()).unwrap_or(i64::MAX);
    vec![
        Datom::new(tx_entity, Attribute::from("tx/time"),
            Value::Instant(now_ms), tx_id, Op::Assert),
        Datom::new(tx_entity, Attribute::from("tx/origin"),
            Value::Ref(EntityId::from_content(node.as_bytes())),
            tx_id, Op::Assert),
    ]
}

/// NEW: Federation metadata datoms.
/// INV-FERR-061: predecessor datoms from Frontier (one per agent).
/// INV-FERR-063: provenance datom.
/// INV-FERR-051: signing datoms (when signed).
fn create_federation_metadata(
    tx_entity: EntityId,
    tx_id: TxId,
    frontier: Option<&Frontier>,
    signing: Option<(TxSignature, TxSigner)>,
    provenance: ProvenanceType,
) -> Vec<Datom> {
    let mut metadata = Vec::new();

    // INV-FERR-061: predecessor datoms (D19: Ref values are predecessor EntityIds)
    if let Some(frontier) = frontier {
        for (_agent_id, pred_tx_id) in frontier.iter() {
            // D16+D19: predecessor entity = tx_entity_from_txid(pred_tx_id)
            let pred_entity = tx_entity_from_txid(*pred_tx_id);
            metadata.push(Datom::new(
                tx_entity, Attribute::from("tx/predecessor"),
                Value::Ref(pred_entity), tx_id, Op::Assert,
            ));
        }
    }

    // INV-FERR-063: provenance datom
    metadata.push(Datom::new(
        tx_entity, Attribute::from("tx/provenance"),
        Value::Keyword(Arc::from(provenance.as_keyword())),
        tx_id, Op::Assert,
    ));

    // INV-FERR-051: signing metadata (only when signed)
    if let Some((sig, signer)) = signing {
        metadata.push(Datom::new(
            tx_entity, Attribute::from("tx/signature"),
            Value::from(sig), tx_id, Op::Assert,
        ));
        metadata.push(Datom::new(
            tx_entity, Attribute::from("tx/signer"),
            Value::from(signer), tx_id, Op::Assert,
        ));
    }

    metadata
}

