// --- ferratomic-invariant/src/lib.rs (NEW proc-macro crate) ---

use proc_macro::TokenStream;
use proc_macro2::TokenStream as TokenStream2;
use quote::quote;
use syn::{parse_macro_input, ItemFn, LitStr};

/// Marks a function as implementing a Ferratomic invariant.
///
/// # Example
///
/// ```ignore
/// #[invariant("INV-FERR-070")]
/// pub fn cold_start(path: &Path) -> Result<Database, FerraError> {
///     // mmap-based zero-copy cold start
/// }
/// ```
///
/// At build time, this attribute writes a trace record to
/// `target/ferratomic-invariant-trace/<crate>.json`. The bd-m8ym genesis
/// tool reads these records and emits `:impl/traces-to` datoms linking
/// the function entity to the invariant entity.
///
/// **Does NOT verify that the function actually satisfies the invariant.**
/// That remains the responsibility of tests, Lean, and Kani. The trace
/// edge is a registration, not a proof.
#[proc_macro_attribute]
pub fn invariant(attr: TokenStream, item: TokenStream) -> TokenStream {
    let invariant_id = parse_macro_input!(attr as LitStr).value();
    let func = parse_macro_input!(item as ItemFn);

    // Validate the invariant ID format (e.g., "INV-FERR-070")
    if !is_valid_invariant_id(&invariant_id) {
        return syn::Error::new_spanned(
            &func.sig.ident,
            format!("invalid invariant ID: {invariant_id} (expected INV-FERR-NNN)"),
        )
        .to_compile_error()
        .into();
    }

    // Extract function metadata
    let fn_name = func.sig.ident.to_string();
    let fn_signature = quote!(#func.sig).to_string();
    let crate_name = std::env::var("CARGO_CRATE_NAME").unwrap_or_default();

    // Write trace record to target/ferratomic-invariant-trace/<crate>.json
    write_trace_record(&crate_name, &fn_name, &invariant_id, &fn_signature);

    // Pass through the original function unchanged
    quote!(#func).into()
}

fn is_valid_invariant_id(id: &str) -> bool {
    // INV-FERR-NNN or INV-FERR-NNNa format
    id.starts_with("INV-FERR-") && id.len() >= 11
}

fn write_trace_record(crate_name: &str, fn_name: &str, invariant_id: &str, signature: &str) {
    // Append-only write to target/ferratomic-invariant-trace/<crate>.json
    // Format: { "fn_name": ..., "invariant_id": ..., "signature": ..., "file": ..., "line": ... }
    todo!()
}

