// --- ADD to properties() in crdt_model.rs ---

// INV-FERR-004: Monotonic Growth.
// The G-Set CRDT guarantees monotonicity by construction:
// - BTreeSet::insert never removes elements (Write)
// - BTreeSet::union never removes elements (DeliverMerge)
// We verify this structurally: after any action, every node's
// datom set is a superset of the previous state's datom set.
//
// Stateright's Property::always checks reachable states, not
// transitions. But we can verify the STRUCTURAL INVARIANT that
// makes monotonicity hold: every node's datom set is always
// a subset of the universal datom set (all writes ever issued).
// A shrinkage would mean a datom disappeared — which is
// impossible if Write and Merge are correctly implemented as
// insert and union.
//
// The most direct check: verify that |nodes[i]| is consistent
// with the number of unique datoms written to or merged into
// node i. Since received_writes already tracks this:
Property::always(
    "inv_ferr_004_monotonic_growth",
    |_: &CrdtModel, state: &CrdtState| {
        // Every datom that a node has received (via write or merge)
        // must still be present in the node's state.
        // received_writes[i] ⊆ nodes[i] — this IS monotonicity.
        for (node, received) in state.nodes.iter().zip(state.received_writes.iter()) {
            if !received.is_subset(node) {
                return false; // A received datom was lost — growth violated
            }
        }
        true
    },
),
```

