// --- MODIFY CrashRecoveryState (in crash_recovery_model.rs) ---

pub struct CrashRecoveryState {
    pub phase: Phase,
    pub committed_store: BTreeSet<Datom>,
    pub recovered_store: BTreeSet<Datom>,
    pub wal: BTreeSet<Datom>,
    pub committed_count: usize,
    /// INV-FERR-005: Abstract secondary index. Must equal committed_store
    /// in every stable state (Idle, Recovered). May diverge transiently
    /// during Writing or after Crash (recovery restores the bijection).
    pub index_set: BTreeSet<Datom>,
}

// --- UPDATE init_states ---
// Add: index_set: BTreeSet::new(),

// --- UPDATE next_state ---
// In Commit arm, after adding to committed_store:
//   next.index_set = next.committed_store.clone(); // atomic: both updated together
// In Recover arm:
//   next.index_set = next.recovered_store.clone(); // recovery rebuilds indexes

// --- ADD to properties() ---
Property::always(
    "inv_ferr_005_index_bijection",
    |_: &CrashRecoveryModel, state: &CrashRecoveryState| {
        match &state.phase {
            Phase::Idle | Phase::Recovered => {
                // In stable states: primary == index (bijection holds)
                state.committed_store == state.index_set
            }
            // During Writing, Crashed, Recovering: bijection may be
            // transiently broken — this is expected and recovery fixes it.
            _ => true,
        }
    },
),
```

