    "inv_ferr_008_wal_fsync_ordering",
    |_: &CrashRecoveryModel, state: &CrashRecoveryState| {
        // During Writing phase: pending datoms must NOT be in committed_store.
        // They become visible only after FsyncWal → Commit sequence.
