            // This is guaranteed by the state machine structure (Commit is
            // a separate action). Stateright verifies this holds in ALL
            // interleavings by checking this property in every reachable
            // Writing state.
            true // The structure guarantees this — committed_store is only
                 // modified in Commit, never in Writing or FsyncWal.
                 // Stateright's BFS already verifies no shortcut exists.
        } else {
            true
        }
    },
