use super::crdt_model::Datom;

/// Abstract value type for schema checking.
#[derive(Clone, Debug, Eq, Hash, PartialEq)]
enum ValueType { String, Long }

/// Schema: maps attribute ID to expected value type.
type SchemaMap = std::collections::BTreeMap<u64, ValueType>;

#[derive(Clone, Debug, Eq, Hash, PartialEq)]
struct SchemaState {
    /// Committed datom store.
    store: std::collections::BTreeSet<Datom>,
    /// Schema derived from store datoms (C3: schema-as-data).
    schema: SchemaMap,
    /// Pending transaction datoms (not yet committed).
    pending: Vec<Datom>,
    /// Whether the pending transaction contains any schema violation.
    has_violation: bool,
}

#[derive(Clone, Debug, Eq, Hash, PartialEq)]
enum SchemaAction {
    /// Add a datom that matches schema to the pending transaction.
    AddValid(Datom),
    /// Add a datom that violates schema type to the pending transaction.
    AddInvalid(Datom),
    /// Commit the pending transaction (if no violations).
    Commit,
    /// Reject the pending transaction (if any violation, or explicit reject).
    Reject,
}

// Property: inv_ferr_009_rejection_preserves_store
// After Reject: store == store_before_transaction. Zero leakage.

// Property: inv_ferr_009_atomicity
// If has_violation is true at Commit time, the Commit action is a no-op
// (or transitions to a rejected state). No partial application.
