## Pseudocode Contract

```rust
impl Store {
    /// Was: calls self.promote(), inserts, calls self.demote()
    /// Now: dispatches to splice_transact for Positional, falls back to
    /// promote/insert/demote for OrdMap (should not normally occur).
    pub fn transact(
        &mut self,
        transaction: Transaction<Committed>,
        tx_id: ferratom::TxId,
    ) -> Result<TxReceipt, FerraError> {
        // ... epoch advance, stamp_datoms, evolve_schema unchanged ...

        match &self.repr {
            StoreRepr::Positional(_) => self.splice_transact(all_datoms)?,
            StoreRepr::OrdMap { .. } => {
                // Fallback: existing promote path for OrdMap-active stores
                for datom in &all_datoms {
                    if let StoreRepr::OrdMap { datoms, indexes } = &mut self.repr {
                        datoms.insert(datom.clone());
                        indexes.insert(datom);
                    }
                    self.live_apply(datom);
                }
                self.demote();
            }
        }

        Ok(TxReceipt { epoch: self.epoch, datoms: all_datoms })
    }

    /// Merge-sort splice: insert K datoms into Positional without OrdMap detour.
    ///
    /// INV-FERR-072: produces identical datom set to promote+insert+demote.
    /// INV-FERR-074: fingerprint updated via XOR homomorphism in O(K).
    /// Cost: O(N + K log K) where N = |canonical|, K = |new_datoms|.
    fn splice_transact(&mut self, new_datoms: Vec<Datom>) -> Result<(), FerraError> {
        if let StoreRepr::Positional(ps) = &self.repr {
            // 1. Sort new datoms into canonical EAVT order: O(K log K)
            let mut sorted_new = new_datoms;
            sorted_new.sort_unstable();

            // 2. Merge into existing canonical: O(N + K)
            let merged = crate::positional::merge_sort_dedup(
                ps.datoms(), &sorted_new
            );

            // 3. Incremental fingerprint: XOR new datom hashes into old fp
            let mut fp = ps.fingerprint();
            for d in &sorted_new {
                let hash = d.content_hash();
                for (acc, byte) in fp.iter_mut().zip(hash.iter()) {
                    *acc ^= byte;
                }
            }

            // 4. Rebuild LIVE bitvector from merged canonical: O(N + K)
            let live_bits = crate::positional::build_live_bitvector(&merged);

            // 5. Construct new PositionalStore with lazy permutations
            let new_ps = PositionalStore::from_merged(merged, fp, live_bits);
            self.repr = StoreRepr::Positional(Arc::new(new_ps));

            // 6. Update live_causal from new datoms only: O(K log M)
            for d in &sorted_new {
                self.live_apply(d);
            }
        }
        Ok(())
    }
}

impl PositionalStore {
    /// Construct from pre-merged canonical array with pre-computed fingerprint
    /// and LIVE bitvector. Permutation arrays are OnceLock::new() (lazy).
    ///
    /// INV-FERR-073: permutations deferred to first access.
    pub(crate) fn from_merged(
        canonical: Vec<Datom>,
        fingerprint: [u8; 32],
        live_bits: BitVec<u64, Lsb0>,
    ) -> Self { todo!() }
}
```

