```rust
//! Unsafe boundary for memory-mapped zero-copy access (ADR-FERR-020).
//!
//! This module is the ONLY location in ferratomic-core where unsafe code
//! is permitted. It provides [`validate_and_cast`] — a BLAKE3-guarded
//! pointer cast from raw bytes to a typed reference.
//!
//! ## Unsafe Budget
//!
//! This bead (bd-erfj): 1 unsafe block in validate_and_cast.
//! Follow-up bead (bd-ta8c): adds MappedStore::archived() (1 more unsafe block)
//!   + memmap2::Mmap::map (1 more unsafe call).
//! Total after both beads: 3 unsafe sites, all in mmap.rs, all pointer casts
//! or OS-level mmap with the same safety invariant (BLAKE3-verified bytes,
//! alignment-checked, repr(C) target type).
#![allow(unsafe_code)]

use ferratom::FerraError;

/// BLAKE3 hash size.
const HASH_SIZE: usize = 32;

/// Marker trait: implementor is repr(C), no padding, all bit patterns valid.
///
/// # Safety
///
/// Only rkyv Archived* types (generated with #[archive(check_bytes)]) should
/// implement this. The implementor MUST be #[repr(C)] with no interior
/// references, pointers, or interior mutability.
pub(crate) unsafe trait ValidMmapTarget: Sized {}

/// BLAKE3-verified cast from raw bytes to typed reference (ADR-FERR-020).
///
/// Byte layout: [content (N bytes) | BLAKE3 hash (32 bytes)]
///
/// Checks performed BEFORE the unsafe cast:
/// 1. Size: bytes.len() >= size_of::<T>() + 32
/// 2. Integrity: blake3(content) == stored_hash
/// 3. Alignment: content pointer aligned to align_of::<T>()
///
/// The unsafe block contains exactly ONE expression: the pointer cast.
///
/// # Errors
///
/// Returns FerraError::CheckpointCorrupted on any check failure.
pub(crate) fn validate_and_cast<'a, T: ValidMmapTarget>(
    bytes: &'a [u8],
) -> Result<&'a T, FerraError> {
    let min_size = HASH_SIZE + std::mem::size_of::<T>();
    if bytes.len() < min_size {
        return Err(FerraError::CheckpointCorrupted {
            expected: format!("at least {min_size} bytes for mmap cast"),
            actual: format!("{} bytes", bytes.len()),
        });
    }

    let (content, stored_hash) = bytes.split_at(bytes.len() - HASH_SIZE);

    let computed = blake3::hash(content);
    if computed.as_bytes() != stored_hash {
        return Err(FerraError::CheckpointCorrupted {
            expected: "valid BLAKE3 checksum".to_string(),
            actual: "checksum mismatch".to_string(),
        });
    }

    let ptr = content.as_ptr();
    let align = std::mem::align_of::<T>();
    if (ptr as usize) % align != 0 {
        return Err(FerraError::CheckpointCorrupted {
            expected: format!("{align}-byte alignment"),
            actual: format!("alignment offset {}", (ptr as usize) % align),
        });
    }

    // SAFETY: All three preconditions verified above.
    // 1. BLAKE3 hash matches — bytes are untampered.
    // 2. content.len() >= size_of::<T>() — sufficient bytes.
    // 3. Pointer aligned to align_of::<T>().
    // 4. T: ValidMmapTarget — repr(C), no padding, all bit patterns valid.
    // 5. Lifetime 'a tied to input slice — reference cannot outlive data.
    Ok(unsafe { &*(ptr as *const T) })
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Test-only repr(C) struct for validate_and_cast tests.
    #[repr(C)]
    #[derive(Debug, PartialEq)]
    struct TestPayload {
        a: u64,
        b: u32,
        // repr(C) padding: 4 bytes after b to align to 8-byte boundary on most platforms.
        // BLAKE3 hash covers ALL bytes including padding — the cast restores identical layout.
    }

    // SAFETY: TestPayload is repr(C). All fields are integer types.
    // All bit patterns of u64 and u32 are valid.
    unsafe impl ValidMmapTarget for TestPayload {}

    /// Helper: build test data with correct BLAKE3 hash.
    fn make_test_data(payload: &TestPayload) -> Vec<u8> {
        let payload_bytes: &[u8] = unsafe {
            std::slice::from_raw_parts(
                (payload as *const TestPayload) as *const u8,
                std::mem::size_of::<TestPayload>(),
            )
        };
        let mut data = payload_bytes.to_vec();
        let hash = blake3::hash(&data);
        data.extend_from_slice(hash.as_bytes());
        data
    }

    #[test]
    fn test_adr_ferr_020_valid_cast() {
        let payload = TestPayload { a: 42, b: 7 };
        let data = make_test_data(&payload);
        let result = validate_and_cast::<TestPayload>(&data);
        assert!(result.is_ok(), "ADR-FERR-020: valid data must cast");
        let reference = result.unwrap();
        assert_eq!(reference.a, 42, "field a must survive roundtrip");
        assert_eq!(reference.b, 7, "field b must survive roundtrip");
    }

    #[test]
    fn test_adr_ferr_020_corrupted_hash() {
        let payload = TestPayload { a: 1, b: 2 };
        let mut data = make_test_data(&payload);
        data[0] ^= 0xFF; // flip a content byte — hash won't match
        assert!(
            validate_and_cast::<TestPayload>(&data).is_err(),
            "ADR-FERR-020: corrupted content must be rejected"
        );
    }

    #[test]
    fn test_adr_ferr_020_too_short() {
        let data = vec![0u8; 10]; // way too short
        assert!(
            validate_and_cast::<TestPayload>(&data).is_err(),
            "ADR-FERR-020: too-short data must be rejected"
        );
    }

    #[test]
    fn test_adr_ferr_020_empty_input() {
        assert!(
            validate_and_cast::<TestPayload>(&[]).is_err(),
            "ADR-FERR-020: empty input must be rejected"
        );
    }

    #[test]
    fn test_adr_ferr_020_hash_only_no_content() {
        let data = vec![0u8; HASH_SIZE]; // just a hash, no content for T
        assert!(
            validate_and_cast::<TestPayload>(&data).is_err(),
            "ADR-FERR-020: hash-only (no content) must be rejected"
        );
    }
}
