            .expect("partial load");

        // Partial store has <= full datoms
        prop_assert!(partial.store.len() <= store.len());

        // Full merge recovers everything
        let full = partial.load_historical();
        prop_assert_eq!(
            full.datom_set(), store.datom_set(),
            "INV-FERR-075: load_historical must recover full datom set"
        );
    }
