pub enum DatomIter<'a> {
    Slice(std::slice::Iter<'a, Datom>),
    OrdSet(im::ordset::Iter<'a, Datom>),
}
impl<'a> Iterator for DatomIter<'a> {
    type Item = &'a Datom;
    fn next(&mut self) -> Option<Self::Item> {
        match self { Self::Slice(it) => it.next(), Self::OrdSet(it) => it.next() }
    }
    fn size_hint(&self) -> (usize, Option<usize>) {
        match self { Self::Slice(it) => it.size_hint(), Self::OrdSet(it) => it.size_hint() }
    }
}
impl ExactSizeIterator for DatomIter<'_> {}

pub enum DatomSetView<'a> {
    Slice(&'a [Datom]),
    OrdSet(&'a OrdSet<Datom>),
}
impl DatomSetView<'_> {
    pub fn contains(&self, d: &Datom) -> bool {
        match self { Self::Slice(s) => s.binary_search(d).is_ok(), Self::OrdSet(s) => s.contains(d) }
    }
    pub fn len(&self) -> usize {
        match self { Self::Slice(s) => s.len(), Self::OrdSet(s) => s.len() }
    }
    pub fn is_empty(&self) -> bool { self.len() == 0 }
    pub fn iter(&self) -> DatomIter<'_> {
        match self { Self::Slice(s) => DatomIter::Slice(s.iter()), Self::OrdSet(s) => DatomIter::OrdSet(s.iter()) }
    }
}
impl PartialEq for DatomSetView<'_> {
    fn eq(&self, other: &Self) -> bool { self.len() == other.len() && self.iter().eq(other.iter()) }
}
impl Eq for DatomSetView<'_> {}
impl std::fmt::Debug for DatomSetView<'_> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result { f.debug_list().entries(self.iter()).finish() }
}

