```rust
pub fn from_merge(a: &Store, b: &Store) -> Self {
    let merged_positional = match (&a.repr, &b.repr) {
        (StoreRepr::Positional(a_pos), StoreRepr::Positional(b_pos)) => {
            positional::merge_positional(a_pos, b_pos)
        }
        (StoreRepr::Positional(a_pos), StoreRepr::OrdMap { datoms: b_d, .. }) => {
            let b_pos = PositionalStore::from_datoms(b_d.iter().cloned());
            positional::merge_positional(a_pos, &b_pos)
        }
        (StoreRepr::OrdMap { datoms: a_d, .. }, StoreRepr::Positional(b_pos)) => {
            let a_pos = PositionalStore::from_datoms(a_d.iter().cloned());
            positional::merge_positional(&a_pos, b_pos)
        }
        (StoreRepr::OrdMap { datoms: a_d, .. }, StoreRepr::OrdMap { datoms: b_d, .. }) => {
            let a_pos = PositionalStore::from_datoms(a_d.iter().cloned());
            let b_pos = PositionalStore::from_datoms(b_d.iter().cloned());
            positional::merge_positional(&a_pos, &b_pos)
        }
    };
    let schema_merge = merge_schemas(&a.schema, &b.schema);
    let epoch = a.epoch.max(b.epoch);
    let genesis_agent = std::cmp::min(a.genesis_agent, b.genesis_agent);
    let live_causal = merge_causal(&a.live_causal, &b.live_causal);
    let live_set = super::query::derive_live_set(&live_causal);
    Self {
        repr: StoreRepr::Positional(Arc::new(merged_positional)),
        schema: schema_merge.schema, epoch, genesis_agent,
        live_causal, live_set, schema_conflicts: schema_merge.conflicts,
    }
}
