// --- ferratom/src/provenance.rs (NEW) ---

use serde::{Serialize, Deserialize};

/// Provenance type: epistemic confidence lattice (INV-FERR-063).
/// Total order: Hypothesized < Inferred < Derived < Observed.
/// Used as `:tx/provenance` metadata datom value (ADR-FERR-028).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum ProvenanceType {
    /// Speculative assertion, lowest confidence (0.2).
    Hypothesized,
    /// Deduced from indirect evidence (0.5).
    Inferred,
    /// Computed from other facts (0.8).
    Derived,
    /// Directly observed or measured (1.0).
    Observed,
}

impl ProvenanceType {
    /// Integer rank for total ordering. Private — used by Ord impl.
    /// NEG-FERR-001: avoids float comparison + .expect().
    fn rank(self) -> u8 {
        match self {
            Self::Hypothesized => 0,  // lowest
            Self::Inferred => 1,
            Self::Derived => 2,
            Self::Observed => 3,      // highest
        }
    }

    /// Confidence weight in [0, 1] (INV-FERR-063 property 4: weight monotonicity).
    #[must_use]
    pub fn confidence(self) -> f64 {
        match self {
            Self::Hypothesized => 0.2,
            Self::Inferred => 0.5,
            Self::Derived => 0.8,
            Self::Observed => 1.0,
        }
    }

    /// Keyword string for datom storage (":provenance/observed" etc).
    #[must_use]
    pub fn as_keyword(&self) -> &'static str {
        match self {
            Self::Hypothesized => ":provenance/hypothesized",
            Self::Inferred => ":provenance/inferred",
            Self::Derived => ":provenance/derived",
            Self::Observed => ":provenance/observed",
        }
    }

    /// Parse a provenance keyword string back to enum.
    /// Returns None for unrecognized keywords.
    /// Used by SignedTransactionBundle::from_store_datoms() (B06) to
    /// reconstruct provenance from Value::Keyword datoms.
    #[must_use]
    pub fn from_keyword(kw: &str) -> Option<Self> {
        match kw {
            ":provenance/hypothesized" => Some(Self::Hypothesized),
            ":provenance/inferred" => Some(Self::Inferred),
            ":provenance/derived" => Some(Self::Derived),
            ":provenance/observed" => Some(Self::Observed),
            _ => None,
        }
    }
}

impl Ord for ProvenanceType {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.rank().cmp(&other.rank())
    }
}

impl PartialOrd for ProvenanceType {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl std::fmt::Display for ProvenanceType {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.as_keyword())
    }
}

