// --- ferratomic-positional/src/moe.rs (NEW, ~400 LOC if pursued) ---

use ferratom::{Datom, EntityId};
use ferratomic_index::EavtKey;
use crate::pgm_eavt::PgmEavtIndex;

const MOE_BUCKET_BITS: usize = 7;
const MOE_NUM_EXPERTS: usize = 1 << MOE_BUCKET_BITS;  // 128

/// Mixture-of-experts learned index for the EAVT canonical array.
///
/// 128 specialized PGM-indexes, each covering a 7-bit prefix partition.
/// Routing: (prefix >> 57) as usize → expert ID. One cycle.
/// Each expert: ~50 segments × 24 bytes = 1.2 KB. All 128: ~150 KB. L2-resident.
pub(crate) struct MoeEavtIndex {
    /// 128 expert indexes, indexed by 7-bit prefix bucket.
    /// Each expert is built lazily on first access via OnceLock.
    experts: [OnceLock<PgmEavtIndex>; MOE_NUM_EXPERTS],
    /// Reference to the canonical array (held via Arc for lifetime stability).
    canonical: Arc<Vec<Datom>>,
    /// Per-expert canonical slice ranges (precomputed at construction).
    /// expert_ranges[i] = (start, end) in canonical[]
    expert_ranges: [(u32, u32); MOE_NUM_EXPERTS],
}

impl MoeEavtIndex {
    /// Build from a sorted canonical Datom array.
    /// O(n) time to compute the per-expert ranges; experts are lazily built.
    pub(crate) fn build(canonical: Arc<Vec<Datom>>) -> Self { todo!() }

    /// Look up a Datom by EavtKey via MoE routing.
    /// O(1) routing + O(log log ε) expert lookup.
    pub(crate) fn lookup<'a>(&'a self, key: &EavtKey) -> Option<&'a Datom> {
        let prefix = entity_prefix_u64(key);
        let expert_id = (prefix >> (64 - MOE_BUCKET_BITS)) as usize;
        let expert = self.experts[expert_id].get_or_init(|| {
            let (start, end) = self.expert_ranges[expert_id];
            PgmEavtIndex::build(&self.canonical[start as usize..end as usize])
        });
        expert.lookup(&self.canonical[..], key)
    }
}

/// Unified entity router: maps a key to its location (local expert OR remote shard).
/// Implemented by both MoeEavtIndex (local) and FederationRouter (remote).
/// Phase 4c sharding refactor introduces this trait.
pub trait EntityRouter {
    fn route(&self, key: &EavtKey) -> RouteTarget;
}

#[derive(Debug, Clone, Copy)]
pub enum RouteTarget {
    /// Local expert: dispatch to MoE index.
    LocalExpert(usize),
    /// Remote shard: dispatch via federation transport.
    RemoteShard(ShardId),
}

// 5 Judgment Calls — research tier sketch:
// 1. Arc/T/Box: Arc<Vec<Datom>> for canonical sharing across experts.
//    Each expert owns its PgmEavtIndex via OnceLock.
// 2. &self vs &mut self: lookup is &self. build is a free function on the type.
// 3. Return types: Option<&'a Datom> with lifetime tied to canonical via Arc.
// 4. Visibility: pub(crate) for MoeEavtIndex; pub for the EntityRouter trait
//    (so federation can implement it).
// 5. Enum match arms: RouteTarget has 2 variants (LocalExpert, RemoteShard).
//    Match must be exhaustive — no wildcards. Adding a new tier requires
//    explicit handling.
```

