use ferratomic_index::EavtKey;

/// A learned index over the EAVT canonical array using piecewise linear
/// regression with bounded error (Ferragina & Vinciguerra 2020).
///
/// The index stores a small set of linear segments approximating the
/// position-of-key function. For BLAKE3-uniform entity prefixes, the
/// approximation is essentially exact with very few segments.
///
/// Lookup: O(log log ε) probes within a bounded window of size 2ε.
/// Memory: O(n / ε²) segments. For ε=32, n=100M: ~50 segments × 24 bytes ≈ 1.2 KB.
pub(crate) struct PgmEavtIndex {
    /// The underlying PGM-index over u64 entity-prefix keys.
    /// Keys are derived from the first 8 bytes of each EntityId.
    inner: pgm::PGMIndex<u64>,
    /// The error bound used to construct the index. Lookups must bounded-scan within ±error_bound.
    error_bound: usize,
}

impl PgmEavtIndex {
    /// Build the PGM-index from a sorted canonical Datom array.
    /// O(n) time for the segment fitting.
    /// Called lazily on first eavt_get access via OnceLock.
    pub(crate) fn build(canonical: &[Datom]) -> Self { todo!() }

    /// Look up a Datom by EavtKey using the PGM model + bounded scan.
    /// Returns Some(&Datom) if found, None otherwise.
    /// O(log log ε) probes; ε is bounded by construction.
    pub(crate) fn lookup<'a>(&self, canonical: &'a [Datom], key: &EavtKey) -> Option<&'a Datom> { todo!() }

    /// Approximate memory size of the PGM model in bytes.
    /// Used for memory-budget tracking.
    pub(crate) fn memory_bytes(&self) -> usize { todo!() }
}

// --- ferratomic-positional/src/store.rs (modified) ---

pub struct PositionalStore {
    pub(crate) canonical: Vec<Datom>,
    pub(crate) live_bits: RoaringBitmap,  // (modified by bd-roaring-live)
    // ... existing fields ...

    /// PGM-index for EAVT lookups (Ferragina-Vinciguerra 2020).
    /// Lazily built on first eavt_get_pgm() call via OnceLock.
    /// Behind feature flag `pgm_eavt`; falls back to interpolation_search
    /// if disabled.
    pub(crate) pgm_eavt: OnceLock<PgmEavtIndex>,
}

impl PositionalStore {
    /// EAVT lookup using PGM-index (ADR-FERR-NNN, Ferragina-Vinciguerra 2020).
    ///
    /// O(log log ε) probes via learned linear segments.
    /// Lazily builds the PGM model on first access.
    ///
    /// Behavior MUST be identical to `eavt_get` (interpolation_search):
    /// returns the same Datom for the same key, or None if absent.
    /// Verified via proptest.
    #[must_use]
    #[cfg(feature = "pgm_eavt")]
    pub fn eavt_get_pgm(&self, key: &EavtKey) -> Option<&Datom> {
        let pgm = self.pgm_eavt.get_or_init(|| PgmEavtIndex::build(&self.canonical));
        pgm.lookup(&self.canonical, key)
    }

    /// EAVT lookup, dispatching to PGM or interpolation search per feature flag.
    /// This is the public lookup API; callers don't need to know which path
    /// is used.
    #[must_use]
    pub fn eavt_get(&self, key: &EavtKey) -> Option<&Datom> {
        #[cfg(feature = "pgm_eavt")]
        {
            self.eavt_get_pgm(key)
        }
        #[cfg(not(feature = "pgm_eavt"))]
        {
            interpolation_search(&self.canonical, key)
        }
    }
}

// --- 5 Judgment Calls Resolved ---
// 1. Arc/T/Box: PgmEavtIndex owns its inner PGMIndex<u64>. Wrapped in OnceLock
//    inside PositionalStore for lazy construction (matches existing patterns
//    for mph, bloom, chunk_fps).
// 2. &self vs &mut self: build is a free function on the struct; lookup is
//    &self. eavt_get and eavt_get_pgm are both &self.
// 3. Return types: Option<&'a Datom> — same lifetime as canonical. NO Option<&T>
//    trap because the lifetime is explicitly tied to the canonical parameter.
// 4. Visibility: pub(crate) for PgmEavtIndex (internal to ferratomic-positional).
//    pub for the new eavt_get_pgm method (so verify tests can call it directly).
//    pub for the unchanged eavt_get (the dispatch wrapper).
// 5. Enum match arms: no new enums introduced. The cfg-gated dispatch in
