/// Entropy-coded columnar checkpoint format (V4).
///
/// Per-column encoding matched to entropy profile (NEG-FERR-007):
/// EntityId: raw (H₀=8.0, incompressible)
/// AttributeId: Huffman (H₀≈2.5, 34x compressible)
/// Value: type-specific (strings: zstd, integers: varint)
/// TxId: delta + varint (H₀≈3, 7x compressible)
/// Op: bitpacked (1 bit, already SoA)
pub fn serialize_v4_columnar(store: &ColumnarStore) -> Vec<u8> {
    let mut buf = Vec::new();
    buf.extend_from_slice(b"CHK4");  // Magic
    buf.extend_from_slice(&4u16.to_le_bytes());  // Version

    // Column 1: EntityId — raw (incompressible)
    encode_raw_column(&mut buf, store.entity_column());

    // Column 2: AttributeId — Huffman coded
    encode_huffman_column(&mut buf, store.attr_column());

    // Column 3: Value — type-tagged, per-type codec
    encode_value_column(&mut buf, store.value_column());

    // Column 4: TxId — delta + varint
    encode_delta_varint_column(&mut buf, store.txid_column());

    // Column 5: Op — already BitVec, store raw
    encode_bitvec(&mut buf, store.op_column());

    // Metadata: epoch, schema, fingerprint, chunk_fps
    encode_metadata(&mut buf, store);

    // BLAKE3 trailer
    let hash = blake3::hash(&buf);
    buf.extend_from_slice(hash.as_bytes());
    buf
}
```

