/// Cargo build script that prepends the spine gate status to stderr.
/// Runs before cargo's compilation log lines, so the user sees the gate status first.
fn main() {
    // cargo:rerun-if-changed tells cargo to re-run this script when the bead state changes
    println!("cargo:rerun-if-changed=.beads/issues.jsonl");
    println!("cargo:rerun-if-env-changed=FERRATOMIC_SKIP_DASHBOARD");

    if std::env::var("FERRATOMIC_SKIP_DASHBOARD").is_ok() {
        return;
    }

    // Run ferratomic-spec status --terse, capture output, write to stderr.
    // If the binary doesn't exist yet (pre-bd-m8ym), print a notice and proceed.
    match run_spine_status() {
        Ok(status) => eprintln!("{}", status),
        Err(SpineStatusError::BinaryNotFound) => {
            eprintln!("ferratomic spine: not yet active (bd-m8ym pending)");
        }
        Err(e) => {
            // Don't fail the build on dashboard errors
            eprintln!("ferratomic spine: status query failed ({}); proceeding with build", e);
        }
    }
}

