// --- Mph struct (keys removed) ---

#[derive(Clone, Debug)]
pub(crate) struct Mph {
    backend: ChdBackend,
    /// entity_first_pos[i] = canonical position of first datom for entity rank i.
    entity_first_pos: Vec<u32>,
    /// Number of unique entities (= entity_first_pos.len()).
    num_entities: usize,
}

impl Mph {
    pub(crate) fn build(
        sorted_keys: &[EntityId],
        first_positions: Vec<u32>,
    ) -> Option<Self> {
        debug_assert_eq!(sorted_keys.len(), first_positions.len());
        let backend = ChdBackend::build(sorted_keys)?;
        let num_entities = sorted_keys.len();
        Some(Self { backend, entity_first_pos: first_positions, num_entities })
    }

    /// O(1) entity -> first canonical position.
    /// Verifies against canonical array (no separate keys storage).
    pub(crate) fn entity_position(
        &self,
        key: &EntityId,
        canonical: &[Datom],
    ) -> Option<u32> {
        if self.num_entities == 0 { return None; }
        let slot = self.backend.lookup(key);
        let key_idx = self.backend.reverse_lookup(slot)?;
        if key_idx >= self.num_entities { return None; }
        let pos = self.entity_first_pos[key_idx];
        // Verify against canonical array — no separate keys vec needed
        if canonical.get(pos as usize).map(|d| d.entity()) == Some(*key) {
            Some(pos)
        } else {
            None
        }
    }
}

// --- PositionalStore::entity_lookup (passes canonical) ---

impl PositionalStore {
    pub fn entity_lookup(&self, eid: &EntityId) -> Option<u32> {
        let mph_opt = self.mph.get_or_init(|| {
            let (keys, positions) = self.unique_entities_with_positions();
            Mph::build(&keys, positions)
            // keys Vec dropped here — not stored in Mph
        });
        if let Some(mph) = mph_opt {
            return mph.entity_position(eid, &self.canonical);
        }
        self.first_datom_position_for_entity(eid)
    }
}
```

## Refinement Sketch
- **Abstract**: The canonical array IS the authoritative key storage. The MPH needs keys only during build() (to compute hash displacements). After build, verification reads from canonical[entity_first_pos[rank]].entity() — zero-copy, no duplication.
- **Concrete**: Mph::build takes &[EntityId] (borrowed, not owned). ChdBackend::build takes &[EntityId]. Neither stores the keys. Verification uses the canonical datom array via entity_first_pos indirection.
- **Coupling**: Requires bd-ifpv (entity_first_pos exists). Verification path: MPH slot -> reverse_lookup -> key_idx -> entity_first_pos[key_idx] -> canonical[pos].entity() == queried key.

## Edge Cases
| Scenario | Behavior |
|----------|----------|
| Absent entity | MPH returns arbitrary slot -> reverse_lookup may return Some(key_idx) -> canonical verification fails -> None |
| Present entity | MPH -> correct slot -> correct key_idx -> canonical[pos].entity() matches -> Some(pos) |
| MPH build failure | OnceLock stores None -> fallback to partition_point |

