## Pseudocode — MappedStore (NO transmute)

```rust
#[cfg(feature = "mmap")]
pub(crate) struct MappedStore {
    mmap: memmap2::Mmap,
    payload_end: usize,  // mmap.len() - HASH_SIZE
    epoch: u64,          // cached from archived at construction
    datom_count: u64,    // cached from archived at construction
}

#[cfg(feature = "mmap")]
pub(crate) fn mmap_cold_start(path: &std::path::Path) -> Result<MappedStore, FerraError> {
    let file = std::fs::File::open(path).map_err(|e| FerraError::Io {
        kind: std::io::ErrorKind::NotFound,
        message: format!("mmap_cold_start: {}: {}", path.display(), e),
    })?;
    let mmap = unsafe { memmap2::MmapOptions::new().map(&file) }
        .map_err(|e| FerraError::Io {
            kind: std::io::ErrorKind::Other,
            message: format!("mmap failed: {}", e),
        })?;
    // validate_and_cast: BLAKE3 verify + size + alignment
    let archived: &rkyv::Archived<MmapPayload> = validate_and_cast(&mmap)?;
    let epoch: u64 = archived.epoch.into();
    let datom_count: u64 = archived.datom_count.into();
    let payload_end = mmap.len() - HASH_SIZE;
    Ok(MappedStore { mmap, payload_end, epoch, datom_count })
}

#[cfg(feature = "mmap")]
impl MappedStore {
    pub(crate) fn epoch(&self) -> u64 { self.epoch }
    pub(crate) fn datom_count(&self) -> u64 { self.datom_count }

    /// Re-derive archived reference from mmap bytes. O(1), no BLAKE3 re-check.
    fn archived(&self) -> &rkyv::Archived<MmapPayload> {
        let content = &self.mmap[..self.payload_end];
        // SAFETY: BLAKE3-verified at construction. Layout validated by rkyv.
        // Mmap alive (self holds it). Page-aligned (mmap guarantee).
        unsafe { &*(content.as_ptr() as *const rkyv::Archived<MmapPayload>) }
    }

    /// Promote to owned PositionalStore. O(n) — copies mapped data to heap.
    /// Phase 4a: bincode deserialize WireDatom → into_trusted() → Datom.
    /// Phase 4b: value pool makes this a thin ID→value mapping instead.
    pub(crate) fn promote_to_positional(&self) -> Result<PositionalStore, FerraError> {
        let archived = self.archived();
        // ArchivedVec<u8> → &[u8] via as_slice()
        let datoms_bytes: &[u8] = archived.datoms_bytes.as_slice();
        // ADR-FERR-010: WireDatom trust boundary
        let wire_datoms: Vec<ferratom::wire::WireDatom> = bincode::deserialize(datoms_bytes)
            .map_err(|e| FerraError::CheckpointCorrupted {
                expected: "valid bincode WireDatom in mmap payload".into(),
                actual: e.to_string(),
            })?;
        let datoms: Vec<Datom> = wire_datoms.into_iter()
            .map(|wd| wd.into_trusted()).collect();
        // Reconstruct BitVec
        let live_bits_len = u64::from(archived.live_bits_len) as usize;
        let words: Vec<u64> = archived.live_bits_words.as_slice()
            .iter().map(|w| u64::from(*w)).collect();
        let mut live_bits = BitVec::<u64, Lsb0>::from_vec(words);
        live_bits.truncate(live_bits_len);
        // Build PositionalStore — pub(crate) field construction, same crate
        Ok(PositionalStore {
            canonical: datoms, live_bits,
            perm_aevt: OnceLock::new(), perm_vaet: OnceLock::new(),
            perm_avet: OnceLock::new(), fingerprint: [0u8; 32],
            cuckoo: OnceLock::new(), mph: OnceLock::new(),
        })
    }
}
