1. Use std::sync::OnceLock (stable since Rust 1.70, in std — no external dependency)
2. OnceLock<Vec<u32>> does NOT implement Clone. PositionalStore must impl Clone manually: clone initialized OnceLock values, leave uninitialized ones as OnceLock::new()
3. from_datoms() builds canonical + live_bits ONLY. Permutations are OnceLock::new()
4. build_permutation() helper is UNCHANGED — called from get_or_init closures
5. merge_positional() result has uninitialized perms (same as from_datoms)
6. Arc<PositionalStore> in StoreRepr means the OnceLock init is shared across all Arc clones — init once, visible to all readers. OnceLock is Sync, so concurrent get_or_init is safe.

## Pseudocode — PositionalStore struct (REPLACE in positional.rs)

```rust
use std::sync::OnceLock;

pub struct PositionalStore {
    canonical: Vec<Datom>,
    live_bits: BitVec<u64, Lsb0>,
    perm_aevt: OnceLock<Vec<u32>>,  // was: Vec<u32>
    perm_vaet: OnceLock<Vec<u32>>,  // was: Vec<u32>
    perm_avet: OnceLock<Vec<u32>>,  // was: Vec<u32>
    fingerprint: [u8; 32],
}

// Manual Clone — OnceLock<T> does not derive Clone
impl Clone for PositionalStore {
    fn clone(&self) -> Self {
        Self {
            canonical: self.canonical.clone(),
            live_bits: self.live_bits.clone(),
            perm_aevt: self.perm_aevt.get().map_or_else(OnceLock::new, |v| {
                let lock = OnceLock::new();
                let _ = lock.set(v.clone()); // infallible on fresh OnceLock
                lock
            }),
            perm_vaet: self.perm_vaet.get().map_or_else(OnceLock::new, |v| {
                let lock = OnceLock::new();
                let _ = lock.set(v.clone());
                lock
            }),
            perm_avet: self.perm_avet.get().map_or_else(OnceLock::new, |v| {
                let lock = OnceLock::new();
                let _ = lock.set(v.clone());
                lock
            }),
            fingerprint: self.fingerprint,
        }
    }
}

// Manual Debug — OnceLock<T> derives Debug if T: Debug, but show init status
impl std::fmt::Debug for PositionalStore {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PositionalStore")
            .field("canonical_len", &self.canonical.len())
            .field("live_bits_len", &self.live_bits.len())
            .field("perm_aevt_init", &self.perm_aevt.get().is_some())
            .field("perm_vaet_init", &self.perm_vaet.get().is_some())
            .field("perm_avet_init", &self.perm_avet.get().is_some())
            .finish()
    }
}
```

