## Pseudocode — Lazy accessors (REPLACE)

```rust
// Helper: get-or-init a permutation array
fn ensure_perm<F, K: Ord>(lock: &OnceLock<Vec<u32>>, canonical: &[Datom], key_fn: F) -> &[u32]
where F: Fn(&Datom) -> K {
    lock.get_or_init(|| build_permutation(canonical, key_fn))
}

pub fn aevt_get(&self, key: &AevtKey) -> Option<&Datom> {
    let perm = self.perm_aevt.get_or_init(|| build_permutation(&self.canonical, AevtKey::from_datom));
    permuted_binary_search(perm, &self.canonical, |d| AevtKey::from_datom(d).cmp(key))
}
pub fn vaet_get(&self, key: &VaetKey) -> Option<&Datom> {
    let perm = self.perm_vaet.get_or_init(|| build_permutation(&self.canonical, VaetKey::from_datom));
    permuted_binary_search(perm, &self.canonical, |d| VaetKey::from_datom(d).cmp(key))
}
pub fn avet_get(&self, key: &AvetKey) -> Option<&Datom> {
    let perm = self.perm_avet.get_or_init(|| build_permutation(&self.canonical, AvetKey::from_datom));
    permuted_binary_search(perm, &self.canonical, |d| AvetKey::from_datom(d).cmp(key))
}
pub fn perm_aevt(&self) -> &[u32] {
    self.perm_aevt.get_or_init(|| build_permutation(&self.canonical, AevtKey::from_datom))
}
pub fn perm_vaet(&self) -> &[u32] {
    self.perm_vaet.get_or_init(|| build_permutation(&self.canonical, VaetKey::from_datom))
}
pub fn perm_avet(&self) -> &[u32] {
    self.perm_avet.get_or_init(|| build_permutation(&self.canonical, AvetKey::from_datom))
}
