pub fn merge_positional(a: &PositionalStore, b: &PositionalStore) -> PositionalStore {
    let merged = merge_sort_dedup(&a.canonical, &b.canonical);
    // Do NOT call from_datoms — that would re-sort an already-sorted Vec.
    // Build directly with lazy perms:
    let live_bits = build_live_bitvector(&merged);
    PositionalStore {
        canonical: merged,
        live_bits,
        perm_aevt: OnceLock::new(), // lazy
        perm_vaet: OnceLock::new(),
        perm_avet: OnceLock::new(),
        fingerprint: [0u8; 32], // recomputed by bd-83j4
    }
}
// build_live_bitvector, build_permutation, merge_sort_dedup, permuted_binary_search — UNCHANGED
