## Pseudocode — PositionalStore integration (positional.rs)

```rust
use crate::mph::Mph;

// Add field to PositionalStore:
mph: OnceLock<Option<Mph>>,

// In manual Clone impl (bd-vhmc pattern):
mph: match self.mph.get() {
    Some(opt) => { let l = OnceLock::new(); let _ = l.set(opt.clone()); l }
    None => OnceLock::new(),
},

// In from_datoms:
mph: OnceLock::new(), // lazy

impl PositionalStore {
    /// O(1) entity → canonical position lookup via CHD MPH (INV-FERR-027).
    ///
    /// MPH confirms entity EXISTS in O(1). If present, find canonical
    /// position via partition_point (O(log n)). For absent entities:
    /// MPH returns false in O(1) → return None immediately.
    #[must_use]
    pub fn entity_lookup(&self, eid: &EntityId) -> Option<u32> {
        let mph_opt = self.mph.get_or_init(|| Mph::build(self.unique_entity_ids()));

        if let Some(mph) = mph_opt {
            if !mph.contains(eid) {
                return None; // O(1) definitive negative
            }
            // Entity confirmed present. Find canonical position.
            return self.first_datom_position_for_entity(eid);
        }

        // MPH build failed → binary search fallback
        self.first_datom_position_for_entity(eid)
    }

    fn first_datom_position_for_entity(&self, eid: &EntityId) -> Option<u32> {
        let pos = self.canonical.partition_point(|d| d.entity() < *eid);
        if pos < self.canonical.len() && self.canonical[pos].entity() == *eid {
            u32::try_from(pos).ok()
        } else {
            None
        }
    }
}
```

