## Pseudocode Contract

```rust
// --- ferratomic-positional/src/prefetch.rs (NEW) ---

//! Cross-architecture software prefetch wrapper.
//!
//! Safe wrapper around platform-specific prefetch intrinsics. Per
//! GOALS.md §6.2 / ADR-FERR-020, internal `unsafe` is permitted because
//! the operation is firewalled behind a safe API: `prefetch_read` takes
//! a `*const T` raw pointer, and the underlying prefetch intrinsic
//! cannot trigger UB regardless of pointer validity (per Intel SDM
//! Vol. 2 PREFETCH instruction docs and ARM ARMv8-A reference manual
//! PRFM instruction docs — prefetch with an invalid address is silently
//! ignored, never faulting).
//!
//! Mission-critical performance: this hides the dominant cache miss in
//! `layout_search` (~80-150 ns per probe → ~20-30 ns hidden behind compare work).

/// Cache locality hint for prefetch.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum CacheLocality {
    /// Bring into L1 cache (most aggressive, retain).
    L1,
    /// Bring into L2 cache (less aggressive).
    L2,
    /// Bring into L3 cache (least aggressive).
    L3,
}

/// Issue a prefetch hint for the cache line containing `ptr`.
///
/// This is a hint, not a guarantee. The CPU may ignore it. The function
/// is safe to call with any pointer (valid, dangling, or null) — prefetch
/// instructions are designed to silently ignore invalid addresses without
/// faulting (per Intel SDM and ARM ARMv8-A reference manuals).
///
/// `&self` semantics: this is a free function, not a method.
/// `*const T`: raw pointer is the input; the function reads no memory.
#[inline(always)]
pub(crate) fn prefetch_read<T>(ptr: *const T, locality: CacheLocality) {
    #[cfg(target_arch = "x86_64")]
    {
        use core::arch::x86_64::{
            _mm_prefetch, _MM_HINT_T0, _MM_HINT_T1, _MM_HINT_T2,
        };
        let hint = match locality {
            CacheLocality::L1 => _MM_HINT_T0,
            CacheLocality::L2 => _MM_HINT_T1,
            CacheLocality::L3 => _MM_HINT_T2,
        };
        // SAFETY: prefetch with any address is safe per Intel SDM Vol. 2.
        // The instruction is a hint and silently ignores invalid addresses.
        unsafe { _mm_prefetch(ptr as *const i8, hint) };
    }

    #[cfg(target_arch = "aarch64")]
    {
        // ARM stable prefetch is more limited; use inline asm for the hint
        // when std::arch::aarch64::__prefetch is unavailable.
        // SAFETY: prefetch with any address is safe per ARM ARMv8-A.
        unsafe {
            core::arch::asm!(
                "prfm pldl1keep, [{ptr}]",
                ptr = in(reg) ptr,
                options(nostack, preserves_flags, readonly),
            );
        }
        // Locality argument is currently ignored on aarch64 (always PLDL1KEEP).
        let _ = locality;
    }

    #[cfg(not(any(target_arch = "x86_64", target_arch = "aarch64")))]
    {
        // No-op fallback for unsupported architectures.
        let _ = ptr;
        let _ = locality;
    }
}

// --- ferratomic-positional/src/perm.rs (modified layout_search) ---

use crate::prefetch::{prefetch_read, CacheLocality};

/// Search an Eytzinger-laid-out permutation array, with software
/// prefetch hints on the canonical array entries for the next two
/// possible probes.
///
/// Identical return value to the non-prefetch version. Prefetch is
/// purely a timing optimization.
#[must_use]
pub(crate) fn layout_search<'a, F>(
    bfs_perm: &[u32],
    canonical: &'a [Datom],
    cmp_fn: F,
) -> Option<&'a Datom>
where
    F: Fn(&Datom) -> std::cmp::Ordering,
{
    let n = bfs_perm.len().saturating_sub(1);
    if n == 0 {
        return None;
    }
    let mut node = 1usize;
    while node <= n {
        // Prefetch the canonical entries for both possible next probes.
        // The hint completes during the comparison below; by the time the
        // next iteration accesses canonical[next_pos], the cache line is warm.
        let left_node = 2 * node;
        let right_node = 2 * node + 1;
        if left_node <= n {
            let left_pos = bfs_perm[left_node] as usize;
            if left_pos < canonical.len() {
                prefetch_read(canonical.as_ptr().wrapping_add(left_pos), CacheLocality::L1);
            }
        }
        if right_node <= n {
            let right_pos = bfs_perm[right_node] as usize;
            if right_pos < canonical.len() {
                prefetch_read(canonical.as_ptr().wrapping_add(right_pos), CacheLocality::L1);
            }
        }

        // Now do the comparison at the current probe — same logic as before.
        let pos = bfs_perm[node] as usize;
        match cmp_fn(&canonical[pos]) {
            std::cmp::Ordering::Equal => return Some(&canonical[pos]),
            std::cmp::Ordering::Less => node = right_node,
            std::cmp::Ordering::Greater => node = left_node,
        }
    }
    None
}

// --- 5 Judgment Calls Resolved ---
// 1. Arc/T/Box: prefetch operates on raw `*const T` which is the canonical
//    array's data pointer plus an offset. No new owned data. The canonical
//    array itself is borrowed via &[Datom] (the parameter to layout_search).
// 2. &self vs &mut self: layout_search takes &[u32], &[Datom], F — all
//    borrowed/owned. No method receiver. prefetch_read is a free function.
// 3. Return types: Option<&'a Datom> — same as before. NO change.
// 4. Visibility: pub(crate) for prefetch_read and CacheLocality (internal
//    to ferratomic-positional). pub(crate) for layout_search (unchanged).
// 5. Enum match arms: CacheLocality has 3 variants (L1, L2, L3). Match in
//    prefetch_read is exhaustive. layout_search match on Ordering has 3
//    variants (Equal, Less, Greater) — also exhaustive. No wildcards.
```

